import React from 'react';
import { useNavigate, Link } from 'react-router-dom';

const Header = ({ userInfo }) => {
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('userInfo');
    navigate('/login');
  };

  return (
    <header style={{
      background: 'linear-gradient(90deg, #f7fafd 0%, #e0e6ed 60%, #0078d4 90%, #d60000 100%)',
      boxShadow: '0 2px 10px rgba(0, 120, 212, 0.07)',
      borderBottom: '1.5px solid #e0e6ed',
      fontFamily: 'Poppins, Inter, sans-serif',
      fontWeight: 500,
      letterSpacing: 0.1,
      zIndex: 100
    }}>
      <div className="container-fluid">
        <div className="d-flex justify-content-between align-items-center">
          <div className="d-flex align-items-center">
            <Link to="/dashboard">
              <img 
                src="/Logo/Sparkle RFID svg.svg" 
                alt="Sparkle RFID" 
                style={{ 
                  height: '48px',
                  marginRight: '30px'
                }} 
              />
            </Link>
            <nav className="d-flex align-items-center">
              <Link 
                to="/dashboard"
                style={{
                  textDecoration: 'none',
                  color: '#0078d4',
                  fontSize: '0.95rem',
                  fontWeight: 600,
                  display: 'flex',
                  alignItems: 'center',
                  padding: '8px 16px',
                  borderRadius: '20px',
                  transition: 'all 0.3s',
                  background: 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)',
                  marginRight: '10px',
                  boxShadow: '0 2px 8px #0078d411',
                  border: '1px solid #e0e6ed'
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)';
                  e.currentTarget.style.color = '#0078d4';
                }}
              >
                <i className="fas fa-home me-2" style={{ color: '#0078d4' }}></i>
                Home
              </Link>
              <Link 
                to="/rfid-integration"
                style={{
                  marginLeft: '10px',
                  textDecoration: 'none', 
                  color: '#0078d4',
                  fontSize: '0.95rem',
                  fontWeight: 600,
                  display: 'flex',
                  alignItems: 'center',
                  padding: '8px 16px',
                  borderRadius: '20px',
                  transition: 'all 0.3s',
                  background: 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)',
                  boxShadow: '0 2px 8px #0078d411',
                  border: '1px solid #e0e6ed'
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)';
                  e.currentTarget.style.color = '#0078d4';
                }}
              >
                <i className="fas fa-plug me-2" style={{ color: '#0078d4' }}></i>
                RFID Integration
              </Link>
              <Link 
                to="/inventory"
                style={{
                  marginLeft: '10px',
                  textDecoration: 'none', 
                  color: '#0078d4',
                  fontSize: '0.95rem',
                  fontWeight: 600,
                  display: 'flex',
                  alignItems: 'center',
                  padding: '8px 16px',
                  borderRadius: '20px',
                  transition: 'all 0.3s',
                  background: 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)',
                  boxShadow: '0 2px 8px #0078d411',
                  border: '1px solid #e0e6ed'
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)';
                  e.currentTarget.style.color = '#0078d4';
                }}
              >
                <i className="fas fa-box me-2" style={{ color: '#0078d4' }}></i>
                Inventory
              </Link>
              <Link 
                to="/upload-rfid"
                style={{
                  marginLeft: '10px',
                  textDecoration: 'none', 
                  color: '#0078d4',
                  fontSize: '0.95rem',
                  fontWeight: 600,
                  display: 'flex',
                  alignItems: 'center',
                  padding: '8px 16px',
                  borderRadius: '20px',
                  transition: 'all 0.3s',
                  background: 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)',
                  boxShadow: '0 2px 8px #0078d411',
                  border: '1px solid #e0e6ed'
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                  e.currentTarget.style.color = '#fff';
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)';
                  e.currentTarget.style.color = '#0078d4';
                }}
              >
                <i className="fas fa-upload me-2" style={{ color: '#0078d4' }}></i>
                Upload EPC Data
              </Link>
            </nav>
          </div>
          {userInfo && (
            <div className="d-flex align-items-center">
              <div style={{
                background: 'linear-gradient(90deg, #e3f0ff 0%, #0078d4 100%)',
                padding: '8px 16px',
                borderRadius: '20px',
                marginRight: '20px',
                display: 'flex',
                alignItems: 'center',
                fontFamily: 'Poppins, Inter, sans-serif',
                fontWeight: 600,
                boxShadow: '0 2px 8px #0078d411',
                border: '1px solid #e0e6ed'
              }}>
                <i className="fas fa-user-circle me-2" style={{ color: '#0078d4' }}></i>
                <span style={{ 
                  fontWeight: 600,
                  color: '#333',
                  marginRight: '12px',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  fontSize: '1.05rem'
                }}>
                  {userInfo.Username}
                </span>
                <span style={{
                  background: 'linear-gradient(90deg, #0078d4 0%, #e3f0ff 100%)',
                  padding: '4px 8px',
                  borderRadius: '12px',
                  fontSize: '0.85rem',
                  color: '#fff',
                  fontWeight: 500
                }}>
                  {userInfo.ClientCode}
                </span>
              </div>
              <button
                onClick={handleLogout}
                style={{
                  background: 'linear-gradient(90deg, #d60000 0%, #ff6161 100%)',
                  color: 'white',
                  border: 'none',
                  padding: '8px 20px',
                  borderRadius: '20px',
                  fontWeight: 600,
                  display: 'flex',
                  alignItems: 'center',
                  transition: 'all 0.3s',
                  boxShadow: '0 4px 15px rgba(214, 0, 0, 0.13)',
                  fontFamily: 'Poppins, Inter, sans-serif',
                  marginLeft: '10px',
                  borderLeft: '1.5px solid #fff'
                }}
                onMouseOver={e => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #ff6161 0%, #d60000 100%)';
                }}
                onMouseOut={e => {
                  e.currentTarget.style.background = 'linear-gradient(90deg, #d60000 0%, #ff6161 100%)';
                }}
              >
                <i className="fas fa-sign-out-alt me-2"></i>
                Logout
              </button>
            </div>
          )}
        </div>
      </div>
    </header>
  );
};

export default Header;
